const t=document.getElementById("burger"),n=document.getElementById("navlinks");t&&n&&(t.addEventListener("click",()=>{const e=n.classList.toggle("open");t.setAttribute("aria-expanded",e?"true":"false")}),n.querySelectorAll("a").forEach(e=>{e.addEventListener("click",()=>{n.classList.remove("open"),t.setAttribute("aria-expanded","false")})}));const a=document.getElementById("lang-en"),l=document.getElementById("lang-es");a&&a.addEventListener("click",()=>{try{localStorage.setItem("vbdn_lang","en")}catch{}});l&&l.addEventListener("click",()=>{try{localStorage.setItem("vbdn_lang","es")}catch{}});
